function evaluateRPNExtended(tokens) {
  const stack = [];
  for (const token of tokens) {
    if (token === 'neg') {
      stack.push(-stack.pop());
      continue;
    }
    if (token === '^') {
      const b = stack.pop();
      const a = stack.pop();
      stack.push(Math.pow(a, b));
      continue;
    }
    if (token === '+' || token === '-' || token === '*' || token === '/') {
      const b = stack.pop();
      const a = stack.pop();
      if (token === '+') { stack.push(a + b); continue; }
      if (token === '-') { stack.push(a - b); continue; }
      if (token === '*') { stack.push(a * b); continue; }
      stack.push(Math.trunc(a / b));
      continue;
    }
    stack.push(Number(token));
  }
  return stack[0];
}
